package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalLooncode;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalLooncodeFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalMapperFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.DmfapplBasisBijdrage;
import be.schaubroeck.lpb.tools.enumtypes.DmfaBezoldigingscode;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Getter;
import lombok.NonNull;
import org.joda.time.LocalDate;

import java.util.List;
import java.util.Set;

@AllArgsConstructor
@Builder
@Getter
public class BerekenWerkbonusDmfapplHelper {
    @NonNull
    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;
    @NonNull
    private final RekenTijd rekenTijd;
    @NonNull
    private final WerkgeversCategorie werkgeversCategorie;
    @NonNull
    private final DmfapplWnkengetal werknemersKengetal;
    @NonNull
    private final AardKodeExtensie loonCode;
    @NonNull
    private final LocalDate datum;

    private static final Set<Integer> EXTRA_LOONCODE_IN_AANMERKING = ImmutableSet.of(318, 328, 338);
    private static final LocalDate EINDE_AANMERKING_WERKBONUS_15 = new LocalDate(2025, 10, 1);

    public boolean isInAanmerkingVoorWerkbonusDmfappl() {
        if (!rekenTijd.getBeginDatum().isBefore(EINDE_AANMERKING_WERKBONUS_15) && DmfaBezoldigingscode.EVG_RSZ_ZIEKTE.getCode().equals(loonCode.getBezoldigingscode())) {
            return false;
        }
        List<DmfapplBasisBijdrage> basisBijdragen = getDmfapplBasisBijdrages();
        boolean bevatWerknemersKengetal = RekenTools.listContains(basisBijdragen, werknemersKengetal);
        boolean bevatBijzondereOpTao = isBevatBijzondereOpTao(basisBijdragen);
        return bevatWerknemersKengetal || bevatBijzondereOpTao || EXTRA_LOONCODE_IN_AANMERKING.contains(loonCode.getCode());
    }

    public List<DmfapplBasisBijdrage> getDmfapplBasisBijdrages() {
        WerknemersKengetalLooncode werknemersKengetalLooncode = WerknemersKengetalLooncodeFactory.create(rekenTijd, loonCode, werknemersKengetal);
        return dmfapplBasisBijdrageService.findByWerkgeversCategorieWerknemersKengetalLooncode(
                werkgeversCategorie, werknemersKengetal, werknemersKengetalLooncode.getLooncodeCode(), datum);
    }

    public boolean isBevatBijzondereOpTao(List<DmfapplBasisBijdrage> basisBijdragen) {
        DmfapplWnkengetal bijzondereOpTao = WerknemersKengetalMapperFactory.getBijzondereOpTao(rekenTijd);
        return RekenTools.listContains(basisBijdragen, bijzondereOpTao);
    }
}
